const updateExistingMediaItem = `-- name: UpdateExistingMediaItem :exec
update app.media_items
set quality_profile_id = coalesce(quality_profile_id, $1::text),
    library_folder_id = coalesce(library_folder_id, $2::uuid),
    media_folder_path = coalesce(media_folder_path, $3::text),
    monitor_mode = $4,
    minimum_availability = $5,
    monitored = $6,
    series_type = coalesce($7::text, series_type),
    updated_at = case
        when (quality_profile_id is null and $1::text is not null)
            or (library_folder_id is null and $2::uuid is not null)
            or (media_folder_path is null and $3::text is not null)
            or monitor_mode <> $4
            or minimum_availability <> $5
            or monitored <> $6
            or ($7::text is not null and series_type is distinct from $7::text)
        then now()
        else updated_at
    end
where id = $8
`

type UpdateExistingMediaItemParams struct {
	QualityProfileID    pgtype.Text
	LibraryFolderID     *uuid.UUID
	MediaFolderPath     pgtype.Text
	MonitorMode         string
	MinimumAvailability string
	Monitored           bool
	SeriesType          pgtype.Text
	ID                  uuid.UUID
}

func (q *Queries) UpdateExistingMediaItem(ctx context.Context, arg UpdateExistingMediaItemParams) error {
	_, err := q.db.Exec(ctx, updateExistingMediaItem,
		arg.QualityProfileID,
		arg.LibraryFolderID,
		arg.MediaFolderPath,
		arg.MonitorMode,
		arg.MinimumAvailability,
		arg.Monitored,
		arg.SeriesType,
		arg.ID,
	)
	return err
}
